import React, { useState, useRef } from 'react';
import { 
  FaUpload, 
  FaSearch, 
  FaFileAlt, 
  FaTrash, 
  FaEdit, 
  FaTimes, 
  FaFilePdf, 
  FaFileWord, 
  FaFileCode,
  FaFile,
  FaCloudUploadAlt,
  FaSpinner,
  FaFilter,
  FaSortAmountDown,
  FaSortAmountUp,
  FaEye,
  FaTag,
  FaCalendarAlt,
  FaWeightHanging
} from 'react-icons/fa';
import toast from 'react-hot-toast';

const DocumentsPage = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [sortBy, setSortBy] = useState('date');
  const [sortOrder, setSortOrder] = useState('desc');
  const [isLoading, setIsLoading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [selectedFile, setSelectedFile] = useState(null);
  const [dragActive, setDragActive] = useState(false);
  const fileInputRef = useRef(null);
  
  const [documents, setDocuments] = useState([
    { 
      id: 1, 
      title: 'FAQ - Common Questions', 
      category: 'faq', 
      date: '2024-01-15', 
      size: '245 KB',
      type: 'pdf',
      description: 'Frequently asked questions about our services',
      tags: ['support', 'help']
    },
    { 
      id: 2, 
      title: 'Product Pricing Guide', 
      category: 'product', 
      date: '2024-01-14', 
      size: '1.2 MB',
      type: 'docx',
      description: 'Complete pricing information for all products',
      tags: ['pricing', 'products']
    },
    { 
      id: 3, 
      title: 'Service Terms & Conditions', 
      category: 'policy', 
      date: '2024-01-13', 
      size: '856 KB',
      type: 'pdf',
      description: 'Terms and conditions for our services',
      tags: ['legal', 'policy']
    },
    { 
      id: 4, 
      title: 'Customer Support Handbook', 
      category: 'service', 
      date: '2024-01-12', 
      size: '3.4 MB',
      type: 'docx',
      description: 'Complete guide for customer support',
      tags: ['support', 'training']
    },
  ]);

  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: 'general',
    tags: '',
  });

  const categories = [
    { value: 'all', label: 'All Categories' },
    { value: 'faq', label: 'FAQ', icon: '❓' },
    { value: 'policy', label: 'Policy', icon: '📋' },
    { value: 'product', label: 'Product', icon: '📦' },
    { value: 'service', label: 'Service', icon: '⚡' },
    { value: 'general', label: 'General', icon: '📄' },
  ];

  const getFileIcon = (type) => {
    switch(type) {
      case 'pdf': return <FaFilePdf className="file-icon pdf" />;
      case 'docx': return <FaFileWord className="file-icon docx" />;
      case 'txt': return <FaFileCode className="file-icon txt" />;
      default: return <FaFile className="file-icon" />;
    }
  };

  const getCategoryColor = (category) => {
    const colors = {
      faq: '#4F46E5',
      policy: '#7C3AED',
      product: '#059669',
      service: '#D97706',
      general: '#6B7280',
    };
    return colors[category] || colors.general;
  };

  const getCategoryBadge = (category) => {
    const labels = {
      faq: 'FAQ',
      policy: 'Policy',
      product: 'Product',
      service: 'Service',
      general: 'General',
    };
    return labels[category] || category;
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const file = e.dataTransfer.files[0];
      handleFileSelect(file);
    }
  };

  const handleFileSelect = (file) => {
    setSelectedFile(file);
    if (!formData.title) {
      setFormData(prev => ({
        ...prev,
        title: file.name.replace(/\.[^/.]+$/, '')
      }));
    }
    toast.success(`File selected: ${file.name}`);
  };

  const handleFileChange = (e) => {
    if (e.target.files && e.target.files[0]) {
      handleFileSelect(e.target.files[0]);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!selectedFile) {
      toast.error('Please select a file to upload');
      return;
    }

    setIsLoading(true);
    setUploadProgress(0);

    const interval = setInterval(() => {
      setUploadProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          return 100;
        }
        return prev + 10;
      });
    }, 200);

    setTimeout(() => {
      clearInterval(interval);
      setUploadProgress(100);
      
      const newDoc = {
        id: documents.length + 1,
        title: formData.title || selectedFile.name,
        description: formData.description || '',
        category: formData.category,
        date: new Date().toISOString().split('T')[0],
        size: (selectedFile.size / 1024).toFixed(1) + ' KB',
        type: selectedFile.name.split('.').pop(),
        tags: formData.tags ? formData.tags.split(',').map(t => t.trim()) : [],
      };
      
      setDocuments(prev => [newDoc, ...prev]);
      toast.success('Document uploaded successfully!');
      
      setIsLoading(false);
      setSelectedFile(null);
      setFormData({ title: '', description: '', category: 'general', tags: '' });
      setShowUploadModal(false);
      setUploadProgress(0);
    }, 2000);
  };

  const handleDelete = (id) => {
    if (window.confirm('Are you sure you want to delete this document?')) {
      setDocuments(documents.filter(doc => doc.id !== id));
      toast.success('Document deleted successfully');
    }
  };

  const filteredDocuments = documents.filter(doc => {
    const matchesSearch = doc.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          doc.description?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          doc.tags?.some(tag => tag.toLowerCase().includes(searchTerm.toLowerCase()));
    const matchesCategory = selectedCategory === 'all' || doc.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const sortedDocuments = [...filteredDocuments].sort((a, b) => {
    if (sortBy === 'date') {
      return sortOrder === 'desc' 
        ? new Date(b.date) - new Date(a.date)
        : new Date(a.date) - new Date(b.date);
    } else if (sortBy === 'title') {
      return sortOrder === 'desc'
        ? b.title.localeCompare(a.title)
        : a.title.localeCompare(b.title);
    } else if (sortBy === 'size') {
      const sizeA = parseFloat(a.size);
      const sizeB = parseFloat(b.size);
      return sortOrder === 'desc' ? sizeB - sizeA : sizeA - sizeB;
    }
    return 0;
  });

  return (
    <div className="documents-page">
      {/* Page Header */}
      <div className="page-header">
        <div className="header-left">
          <h1 className="page-title">📄 Documents</h1>
          <p className="page-subtitle">Manage your business documents and knowledge base</p>
        </div>
        <div className="header-actions">
          <button 
            className="btn-primary upload-btn"
            onClick={() => setShowUploadModal(true)}
          >
            <FaCloudUploadAlt /> Upload Document
          </button>
        </div>
      </div>

      {/* Stats */}
      <div className="stats-row">
        <div className="stat-item">
          <span className="stat-value">{documents.length}</span>
          <span className="stat-label">Total Documents</span>
        </div>
        <div className="stat-item">
          <span className="stat-value">{documents.filter(d => d.category === 'faq').length}</span>
          <span className="stat-label">FAQs</span>
        </div>
        <div className="stat-item">
          <span className="stat-value">{documents.filter(d => d.category === 'product').length}</span>
          <span className="stat-label">Products</span>
        </div>
        <div className="stat-item">
          <span className="stat-value">{documents.filter(d => d.category === 'policy').length}</span>
          <span className="stat-label">Policies</span>
        </div>
      </div>

      {/* Controls */}
      <div className="document-controls">
        <div className="search-box">
          <FaSearch className="search-icon" />
          <input
            type="text"
            placeholder="Search documents by title, description, or tags..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="search-input"
          />
          {searchTerm && (
            <button className="clear-search" onClick={() => setSearchTerm('')}>
              <FaTimes />
            </button>
          )}
        </div>

        <div className="filter-group">
          <div className="filter-box">
            <FaFilter className="filter-icon" />
            <select 
              className="filter-select"
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
            >
              {categories.map(cat => (
                <option key={cat.value} value={cat.value}>
                  {cat.icon} {cat.label}
                </option>
              ))}
            </select>
          </div>

          <div className="sort-box">
            <select 
              className="sort-select"
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value)}
            >
              <option value="date">📅 Date</option>
              <option value="title">📝 Title</option>
              <option value="size">📦 Size</option>
            </select>
            <button 
              className="sort-direction"
              onClick={() => setSortOrder(prev => prev === 'desc' ? 'asc' : 'desc')}
            >
              {sortOrder === 'desc' ? <FaSortAmountDown /> : <FaSortAmountUp />}
            </button>
          </div>
        </div>
      </div>

      {/* Document Grid */}
      {sortedDocuments.length === 0 ? (
        <div className="empty-state">
          <FaFileAlt className="empty-icon" />
          <h3>No documents found</h3>
          <p>Upload your first document to get started</p>
          <button className="btn-primary" onClick={() => setShowUploadModal(true)}>
            <FaUpload /> Upload Document
          </button>
        </div>
      ) : (
        <div className="document-grid">
          {sortedDocuments.map((doc) => (
            <div key={doc.id} className="document-card">
              <div className="card-header">
                <div className="file-icon-wrapper">
                  {getFileIcon(doc.type)}
                </div>
                <div className="card-info">
                  <h4 className="card-title">{doc.title}</h4>
                  {doc.description && (
                    <p className="card-description">{doc.description}</p>
                  )}
                </div>
                <span className="category-badge" style={{ background: getCategoryColor(doc.category) }}>
                  {getCategoryBadge(doc.category)}
                </span>
              </div>
              
              {doc.tags && doc.tags.length > 0 && (
                <div className="card-tags">
                  {doc.tags.map((tag, index) => (
                    <span key={index} className="tag">
                      <FaTag className="tag-icon" /> {tag}
                    </span>
                  ))}
                </div>
              )}
              
              <div className="card-footer">
                <div className="card-meta">
                  <span>
                    <FaCalendarAlt className="meta-icon" />
                    {doc.date}
                  </span>
                  <span>
                    <FaWeightHanging className="meta-icon" />
                    {doc.size}
                  </span>
                </div>
                <div className="card-actions">
                  <button className="action-btn view" title="View">
                    <FaEye />
                  </button>
                  <button className="action-btn edit" title="Edit">
                    <FaEdit />
                  </button>
                  <button 
                    className="action-btn delete" 
                    onClick={() => handleDelete(doc.id)} 
                    title="Delete"
                  >
                    <FaTrash />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Upload Modal */}
      {showUploadModal && (
        <div className="modal-overlay" onClick={() => {
          if (!isLoading) setShowUploadModal(false);
        }}>
          <div className="modal-content upload-modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <div className="modal-header-content">
                <h3><FaCloudUploadAlt /> Upload Document</h3>
                <p>Upload documents to improve your AI assistant's knowledge</p>
              </div>
              <button 
                className="close-btn" 
                onClick={() => {
                  if (!isLoading) setShowUploadModal(false);
                }}
                disabled={isLoading}
              >
                <FaTimes />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="upload-form">
              <div className="form-row">
                <div className="form-group">
                  <label>Document Title <span className="required">*</span></label>
                  <input
                    type="text"
                    name="title"
                    value={formData.title}
                    onChange={handleInputChange}
                    placeholder="Enter document title"
                    className="form-input"
                    required
                  />
                </div>

                <div className="form-group">
                  <label>Category <span className="required">*</span></label>
                  <select
                    name="category"
                    value={formData.category}
                    onChange={handleInputChange}
                    className="form-select"
                    required
                  >
                    {categories.filter(c => c.value !== 'all').map(cat => (
                      <option key={cat.value} value={cat.value}>
                        {cat.icon} {cat.label}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="form-group">
                <label>Description</label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  placeholder="Enter document description"
                  className="form-textarea"
                  rows="2"
                />
              </div>

              <div className="form-group">
                <label>Tags (comma-separated)</label>
                <input
                  type="text"
                  name="tags"
                  value={formData.tags}
                  onChange={handleInputChange}
                  placeholder="e.g., support, pricing, faq"
                  className="form-input"
                />
              </div>

              <div 
                className={`file-upload-area ${dragActive ? 'drag-active' : ''} ${selectedFile ? 'file-selected' : ''}`}
                onDragEnter={handleDrag}
                onDragLeave={handleDrag}
                onDragOver={handleDrag}
                onDrop={handleDrop}
              >
                <input
                  type="file"
                  ref={fileInputRef}
                  onChange={handleFileChange}
                  className="file-input"
                  accept=".pdf,.docx,.txt,.md"
                />
                {selectedFile ? (
                  <div className="file-selected-info">
                    <FaFileAlt className="selected-file-icon" />
                    <div className="file-info">
                      <span className="file-name">{selectedFile.name}</span>
                      <span className="file-size">
                        {(selectedFile.size / 1024).toFixed(1)} KB
                      </span>
                    </div>
                    <button 
                      type="button"
                      className="remove-file"
                      onClick={() => setSelectedFile(null)}
                    >
                      <FaTimes />
                    </button>
                  </div>
                ) : (
                  <div className="file-drop-content">
                    <FaCloudUploadAlt className="upload-icon" />
                    <span className="drop-text">Drag & drop your file here</span>
                    <span className="drop-subtext">or click to browse</span>
                    <span className="file-types">Supports: PDF, DOCX, TXT, MD (Max 10MB)</span>
                  </div>
                )}
              </div>

              {isLoading && (
                <div className="upload-progress">
                  <div className="progress-bar">
                    <div 
                      className="progress-fill" 
                      style={{ width: `${uploadProgress}%` }}
                    ></div>
                  </div>
                  <span className="progress-text">{uploadProgress}% uploaded</span>
                </div>
              )}

              <div className="form-actions">
                <button 
                  type="button" 
                  className="btn-secondary"
                  onClick={() => {
                    if (!isLoading) setShowUploadModal(false);
                  }}
                  disabled={isLoading}
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="btn-primary upload-submit"
                  disabled={isLoading || !selectedFile}
                >
                  {isLoading ? (
                    <>
                      <FaSpinner className="spinner" /> Uploading...
                    </>
                  ) : (
                    <>
                      <FaUpload /> Upload Document
                    </>
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DocumentsPage;












